import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { toast } from 'react-toastify';
import { useAuth } from '../context/AuthContext';

export default function AdminLogin() {
  const [form, setForm] = useState({ email: '', password: '' });
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await login(form.email, form.password, true);
      toast.success('Admin access granted');
      navigate('/admin');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Invalid admin credentials');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center px-4" style={{ background: '#0a0d1a' }}>
      <div style={{ background: '#111827', border: '1px solid #374151', width: '100%', maxWidth: 400 }}
           className="p-8 rounded-2xl">
        <div style={{ color: '#f59e0b' }} className="text-3xl mb-4 text-center">⚙</div>
        <h1 style={{ fontFamily: 'Syne, sans-serif' }} className="text-2xl font-bold mb-1 text-center">Admin Access</h1>
        <p className="text-gray-500 text-sm mb-8 text-center">Restricted to authorized personnel only</p>

        <form onSubmit={e => { e.preventDefault(); handleSubmit(e); }} className="space-y-4">
          <div>
            <label className="block text-sm text-gray-400 mb-1.5">Admin Email</label>
            <input type="email" value={form.email} onChange={e => setForm({...form, email: e.target.value})} required
              style={{ background: '#0a0d1a', border: '1px solid #374151', color: 'white' }}
              className="w-full px-4 py-3 rounded-xl text-sm focus:outline-none focus:border-yellow-500 transition-colors"
              placeholder="admin@backersphere.com" />
          </div>
          <div>
            <label className="block text-sm text-gray-400 mb-1.5">Password</label>
            <input type="password" value={form.password} onChange={e => setForm({...form, password: e.target.value})} required
              style={{ background: '#0a0d1a', border: '1px solid #374151', color: 'white' }}
              className="w-full px-4 py-3 rounded-xl text-sm focus:outline-none focus:border-yellow-500 transition-colors"
              placeholder="••••••••" />
          </div>
          <button type="submit" disabled={loading}
            style={{ background: '#f59e0b', color: '#0a0d1a' }}
            className="w-full py-3 rounded-xl font-bold text-sm hover:opacity-90 transition-all disabled:opacity-60">
            {loading ? 'Authenticating...' : 'Access Admin Panel'}
          </button>
        </form>
      </div>
    </div>
  );
}
